            while ($notFound) {
                $league_id = rand(1, $maxLeagues);
                $league = League::where('id', $league_id)->first();
                if (!$league || ($league->league_type_id == 1 && $league->free_slots < 5) || ($league->league_type_id != 1 && $league->free_slots == 0)) {
                    continue;
                }
                $avatar_id = rand(1, 108);
